import React, { useState, useEffect } from 'react';
import { Box, Heading, Button, Flex, Table, Tbody, Td, Th, Thead, Tr, useToast, Spinner, Input } from '@chakra-ui/react';
import ReactSelect from 'react-select';
import axios from 'axios';
import moment from 'moment';
import * as XLSX from 'xlsx';

const AdminDashboard = () => {
  const [view, setView] = useState('realTime'); // 'realTime' or 'browseAndDownload'
  const [currentTasks, setCurrentTasks] = useState([]);
  const [allTeamMembers, setAllTeamMembers] = useState([]);
  const [selectedTeamMembers, setSelectedTeamMembers] = useState([]);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [tasksData, setTasksData] = useState([]);
  const [loading, setLoading] = useState(true);
  const toast = useToast();

  // Helper function to format time into h m s
  const formatTimeElapsed = (seconds) => {
    const duration = moment.duration(seconds, 'seconds');
    return `${duration.hours()}h ${duration.minutes()}m ${duration.seconds()}s`;
  };

  // Fetch All Team Members
  const fetchAllTeamMembers = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/tasks/team-members', {
        headers: {
          Authorization: `Bearer ${localStorage.getItem('authToken')}`,
        },
      });
      const teamMembers = response.data.map((member) => ({
        value: member._id,
        label: `${member.firstName} ${member.lastName}`,
      }));
      setAllTeamMembers(teamMembers);
    } catch (error) {
      console.error('Error fetching team members:', error);
      toast({
        title: 'Error',
        description: 'Failed to fetch team members. Please try again.',
        status: 'error',
        duration: 3000,
        isClosable: true,
      });
    }
  };

  useEffect(() => {
    fetchAllTeamMembers();
  }, []);

  // Fetch Current Tasks for Real-Time Monitoring
  const fetchCurrentTasks = async () => {
    setLoading(true);
    try {
      const response = await axios.get('http://localhost:5000/api/tasks/current-tasks', {
        headers: {
          Authorization: `Bearer ${localStorage.getItem('authToken')}`,
        },
      });

      const fetchedTasks = response.data.map(userTask => {
        if (userTask.activeTask && !userTask.activeTask.completed) {
          // Calculate the elapsed time dynamically
          const elapsedSeconds = Math.floor((Date.now() - new Date(userTask.activeTask.createdAt).getTime()) / 1000);
          userTask.activeTask.timeSpentFormatted = formatTimeElapsed(elapsedSeconds);
        }
        return userTask;
      });

      setCurrentTasks(fetchedTasks);
    } catch (error) {
      console.error('Error fetching current tasks:', error);
      toast({
        title: 'Error',
        description: 'Failed to fetch tasks. Please try again.',
        status: 'error',
        duration: 3000,
        isClosable: true,
      });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    let intervalId;

    if (view === 'realTime') {
      fetchCurrentTasks();
      intervalId = setInterval(fetchCurrentTasks, 5000); // Refresh every 5 seconds
    }

    return () => {
      if (intervalId) clearInterval(intervalId);
    };
  }, [view]);

  // Use an interval to update time spent dynamically for each active task
  useEffect(() => {
    let intervalId;

    if (view === 'realTime') {
      intervalId = setInterval(() => {
        setCurrentTasks((prevTasks) =>
          prevTasks.map((task) => {
            if (task.activeTask && !task.activeTask.completed) {
              // Calculate elapsed seconds since task was created
              const elapsedSeconds = Math.floor((Date.now() - new Date(task.activeTask.createdAt).getTime()) / 1000);
              return {
                ...task,
                activeTask: {
                  ...task.activeTask,
                  timeSpentFormatted: formatTimeElapsed(elapsedSeconds),
                },
              };
            }
            return task; // Return the task unchanged if it's completed
          })
        );
      }, 1000); // Update every second
    }

    return () => {
      if (intervalId) clearInterval(intervalId);
    };
  }, [view]);

  // Fetch tasks based on selected team members and date range
  // Fetch tasks based on selected team members and date range
const fetchTasksByTeamMemberAndDate = async () => {
  if (!startDate || !endDate || !selectedTeamMembers || selectedTeamMembers.length === 0) {
    toast({
      title: 'Missing Information',
      description: 'Please select a date range and at least one team member.',
      status: 'warning',
      duration: 3000,
      isClosable: true,
    });
    return;
  }

  setLoading(true);

  try {
    // Extract user IDs from selected team members and create a comma-separated string
    const userIds = selectedTeamMembers.map(member => member.value).join(',');

    const response = await axios.get('http://localhost:5000/api/tasks/tasks-by-team-member', {
      params: {
        startDate,
        endDate,
        userIds, // Pass user IDs as a comma-separated string
      },
      headers: {
        'Authorization': `Bearer ${localStorage.getItem('authToken')}`,
      },
    });
    setTasksData(response.data.tasks);
  } catch (error) {
    console.error('Error fetching tasks:', error);
    toast({
      title: 'Error',
      description: 'Failed to fetch tasks. Please try again.',
      status: 'error',
      duration: 3000,
      isClosable: true,
    });
  } finally {
    setLoading(false);
  }
};

  // Export tasks to Excel
  const exportToExcel = () => {
    if (tasksData.length === 0) {
      toast({
        title: 'No Data',
        description: 'No tasks available to export.',
        status: 'warning',
        duration: 3000,
        isClosable: true,
      });
      return;
    }

    const worksheet = XLSX.utils.json_to_sheet(
      tasksData.map(task => ({
        'Task ID': task.taskId,
        Queue: task.queue,
        'Time Spent (s)': task.timeSpent,
        'Date Completed': new Date(task.createdAt).toLocaleDateString(),
      }))
    );

    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, 'Team Member Tasks');

    const teamMemberNames = selectedTeamMembers.map(member => member.label.replace(/\s/g, '_')).join('_');
    const dateRange = `${moment(startDate).format('YYYYMMDD')}_to_${moment(endDate).format('YYYYMMDD')}`;
    const fileName = `tasks_${teamMemberNames}_${dateRange}.xlsx`;

    XLSX.writeFile(workbook, fileName);
  };

  return (
    <Box maxW="80%" mx="auto" mt={10} p={5} borderWidth={1} borderRadius="lg">
      <Heading as="h3" size="lg" mb={6} textAlign="center">
        Admin Dashboard
      </Heading>

      {/* Panel for Selecting View */}
      <Flex justifyContent="center" mb={6}>
        <Button colorScheme="teal" mr={4} onClick={() => setView('realTime')}>
          Real-Time Data
        </Button>
        <Button colorScheme="blue" onClick={() => setView('browseAndDownload')}>
          Download Data
        </Button>
      </Flex>

      {/* Real-Time Data View */}
      {view === 'realTime' && (
        <Box>
          <Heading as="h4" size="md" mb={4}>
            Current Status of Team Members
          </Heading>
          {loading ? (
            <Spinner size="lg" />
          ) : (
            <Table variant="striped" colorScheme="teal">
              <Thead>
                <Tr>
                  <Th>Team Member</Th>
                  <Th>Status</Th>
                  <Th>Task ID</Th>
                  <Th>Queue</Th>
                  <Th>Time Spent (so far)</Th>
                </Tr>
              </Thead>
              <Tbody>
                {currentTasks.map(({ user, activeTask }) => (
                  <Tr key={user.email}>
                    <Td>{`${user.firstName} ${user.lastName}`}</Td>
                    <Td>{activeTask && !activeTask.completed ? 'Active' : 'Idle'}</Td>
                    <Td>{activeTask && !activeTask.completed ? activeTask.taskId : '-'}</Td>
                    <Td>{activeTask && !activeTask.completed ? activeTask.queue : '-'}</Td>
                    <Td>{activeTask && !activeTask.completed ? activeTask.timeSpentFormatted : 'N/A'}</Td>
                  </Tr>
                ))}
              </Tbody>
            </Table>
          )}
        </Box>
      )}

      {/* Browse and Download Data View */}
      {view === 'browseAndDownload' && (
        <Box>
          <Heading as="h4" size="md" mb={4}>
            Download Tasks by Date and Team Member
          </Heading>
          <Flex justifyContent="center" mb={4}>
            <Input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              placeholder="Start Date"
              mx={2}
            />
            <Input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              placeholder="End Date"
              mx={2}
            />
            <ReactSelect
              placeholder="Select Team Members"
              options={allTeamMembers}
              value={selectedTeamMembers}
              onChange={(selectedOptions) => setSelectedTeamMembers(selectedOptions)}
              isMulti
              isClearable
              mx={2}
              styles={{ container: (base) => ({ ...base, width: '300px', marginLeft: '8px' }) }}
            />
          </Flex>
          <Button colorScheme="teal" onClick={fetchTasksByTeamMemberAndDate} mb={4}>
            Fetch Tasks
          </Button>

          {loading ? (
            <Spinner size="lg" />
          ) : (
            tasksData.length > 0 && (
              <Box>
                <Table variant="striped" colorScheme="teal" mt={4}>
                  <Thead>
                    <Tr>
                      <Th>Task ID</Th>
                      <Th>Queue</Th>
                      <Th>Time Spent (s)</Th>
                      <Th>Date Completed</Th>
                    </Tr>
                  </Thead>
                  <Tbody>
                    {tasksData.map(task => (
                      <Tr key={task._id}>
                        <Td>{task.taskId}</Td>
                        <Td>{task.queue}</Td>
                        <Td>{task.timeSpent}</Td>
                        <Td>{new Date(task.createdAt).toLocaleDateString()}</Td>
                      </Tr>
                    ))}
                  </Tbody>
                </Table>

                <Button colorScheme="blue" mt={4} onClick={exportToExcel}>
                  Export to Excel
                </Button>
              </Box>
            )
          )}
        </Box>
      )}
    </Box>
  );
};

export default AdminDashboard;
